mapper.update:
update product
name=#{name}, category_id=#{categoryId}, brand_id=#{brandId}, price=#{price}, inventory=#{inventory}, image=#{image}, description=#{description}, label=#{label}, status=#{status}, update_time=#{updateTime},update_user=#{updateUser}
where id=#{id}

mapper.select:
select p.*,pc.name as categoryName,pb.name as brandName from product as p,product_category as pc,product_brand as pb where p.category_id = pc.id and p.brand_id = pb.id
and pc.name in
#{item}
and pb.name in
#{item}
and p.price between #{minPrice} and #{maxPrice} and p.status = 1 order by id
